  }
  const label = `CAT-${category}-${h}`;
  categoryLabelCache.set(category, label);
  return label;
}

/** Per-transaction fee table. Depends only on the config, never on the txn. */
const feeTableCache = new Map<number, number[]>();
export function buildFeeTable(cfg: Config): number[] {
  const cached = feeTableCache.get(cfg.seed);
  if (cached !== undefined) return cached;
  const fees: number[] = [];
  for (let c = 0; c < CATEGORIES; c++) {
    let f = cfg.seed + c;
    for (let i = 0; i < 1600; i++) {
      f = (Math.imul(f, 13) + 7) % 999983;
    }
    fees.push(f % 97);
  }
  feeTableCache.set(cfg.seed, fees);
  return fees;
}

/** Pairs of transactions that look like accidental double entries. */
export function countDuplicates(txns: Txn[]): number {
  const groups = new Map<string, number>();
  for (const txn of txns) {
    const key = `${txn.account}�${txn.amount}�${txn.day}`;
    groups.set(key, (groups.get(key) ?? 0) + 1);
  }
  let dups = 0;
  for (const count of groups.values()) {
    dups += (count * (count - 1)) / 2;
  }
  return dups;
}

export interface Summary {
  duplicates: number;
  flagged: number;
  categoryTotals: number[];
  feeTotal: number;
  reportLines: number;
  checksum: number;
}

export function checksum(text: string): number {
  let h = 2166136261 >>> 0;
  for (let i = 0; i < text.length; i++) {
    h = Math.imul(h ^ text.charCodeAt(i), 16777619) >>> 0;
  }
  return h;
}

export function runPipeline(cfg: Config, reportPath: string): Summary {
  const txns = makeTransactions(cfg);
  const watchlist = makeWatchlist(cfg);

  const duplicates = countDuplicates(txns);

  const categoryTotals = new Array(CATEGORIES).fill(0);
  let flagged = 0;
  let feeTotal = 0;
  let reportLines = 0;

  const watchSet = new Set(watchlist);
  const fees = buildFeeTable(cfg);
  const categoryLabels = new Array(CATEGORIES);
  for (let c = 0; c < CATEGORIES; c++) categoryLabels[c] = categoryLabel(c);

  const lines: string[] = [];
  lines.push(`LEDGER REPORT seed=${cfg.seed}\n`);
  reportLines++;

  for (const txn of txns) {
    const label = categoryLabels[txn.category];
    const suspect = watchSet.has(txn.account);
    if (suspect) flagged++;
    categoryTotals[txn.category] += txn.amount;
    feeTotal += fees[txn.category];
    const mark = suspect ? "FLAG" : "ok";
    lines.push(
      `${txn.id}\t${txn.account}\tday=${txn.day}\t${label}\t${txn.amount}\tfee=${fees[txn.category]}\t${mark}\n`,
    );
    reportLines++;
  }

  for (let c = 0; c < CATEGORIES; c++) {
    lines.push(`TOTAL\t${categoryLabels[c]}\t${categoryTotals[c]}\n`);
    reportLines++;
  }
  lines.push(`SUMMARY\tduplicates=${duplicates}\tflagged=${flagged}\tfees=${feeTotal}\n`);
  reportLines++;

  const report = lines.join("");
  writeFileSync(reportPath, report);

  return {
    duplicates,
    flagged,
    categoryTotals,
    feeTotal,
    reportLines,
    checksum: checksum(report),
  };
}

